import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import {
  Box,
  Container,
  Typography,
  Button,
  Paper,
  Grid,
  Card,
  CardContent,
  Divider,
  CircularProgress,
  Alert,
  Fade,
  Avatar,
  Chip
} from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import { useTheme } from '@mui/material/styles';

const VerifyPage = () => {
  const { id } = useParams();
  const theme = useTheme();
  const [testimonial, setTestimonial] = useState(null);
  const [isVerified, setIsVerified] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Simulate API call to fetch testimonial
    setTimeout(() => {
      setTestimonial({
        id,
        businessName: 'Growth Coaching',
        original: 'The coaching was good. I learned some things that helped me.',
        enhanced: 'Working with this coach transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. The coaching didnt just teach me tactics—it changed my entire mindset about whats possible.',
        clientName: 'John Doe',
      });
      setIsLoading(false);
    }, 1000);
  }, [id]);

  const handleVerify = () => {
    // Simulate API call to verify testimonial
    setIsVerified(true);
  };

  if (isLoading) {
    return (
      <Container maxWidth="md" sx={{ py: 10 }}>
        <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '50vh' }}>
          <CircularProgress />
        </Box>
      </Container>
    );
  }

  if (isVerified) {
    return (
      <Container maxWidth="md" sx={{ py: 10 }}>
        <Fade in={true}>
          <Card 
            sx={{ 
              p: 6, 
              textAlign: 'center',
              borderRadius: 3,
              maxWidth: 600,
              mx: 'auto'
            }}
          >
            <Box 
              sx={{ 
                width: 80,
                height: 80,
                borderRadius: '50%',
                bgcolor: 'success.light',
                color: 'success.main',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                mx: 'auto',
                mb: 3
              }}
            >
              <CheckCircleIcon sx={{ fontSize: 40 }} />
            </Box>

            <Typography variant="h4" gutterBottom>
              Thank you for verifying!
            </Typography>

            <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
              Your testimonial has been approved and will help others make informed decisions.
            </Typography>

            <Chip 
              icon={<VerifiedUserIcon />} 
              label="Verified Testimonial" 
              color="success"
              sx={{ fontWeight: 600 }}
            />
          </Card>
        </Fade>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 10 }}>
      <Fade in={true}>
        <Box>
          <Typography variant="h3" align="center" gutterBottom>
            {testimonial.businessName} would like you to verify your testimonial
          </Typography>

          <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 6 }}>
            Please review the enhanced version of your testimonial below
          </Typography>

          <Card 
            elevation={0} 
            sx={{ 
              mb: 6,
              borderRadius: 3,
              border: '1px solid rgba(0, 0, 0, 0.08)',
              overflow: 'hidden'
            }}
          >
            <Grid container>
              <Grid item xs={12} md={5} sx={{ 
                bgcolor: 'grey.50', 
                p: 4,
                borderRight: { md: '1px dashed rgba(0, 0, 0, 0.1)' },
                borderBottom: { xs: '1px dashed rgba(0, 0, 0, 0.1)', md: 'none' }
              }}>
                <Typography variant="overline" color="text.secondary" sx={{ fontWeight: 600 }}>
                  YOUR ORIGINAL WORDS
                </Typography>
                <Typography variant="body1" sx={{ mt: 2 }}>
                  {testimonial.original}
                </Typography>
              </Grid>

              <Grid item xs={12} md={7} sx={{ 
                p: 4,
                bgcolor: 'primary.light',
                position: 'relative'
              }}>
                <Typography variant="overline" color="primary.dark" sx={{ fontWeight: 600 }}>
                  ENHANCED VERSION
                </Typography>
                <Typography variant="body1" sx={{ mt: 2, color: 'primary.dark', fontWeight: 500 }}>
                  {testimonial.enhanced}
                </Typography>
              </Grid>
            </Grid>
          </Card>

          <Box sx={{ textAlign: 'center', maxWidth: 600, mx: 'auto' }}>
            <Typography variant="h5" gutterBottom>
              Does this enhanced version accurately represent your experience?
            </Typography>

            <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
              By approving, you confirm this testimonial is truthful and can be used in marketing.
            </Typography>

            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 3 }}>
              <Button 
                variant="contained" 
                color="primary"
                size="large"
                onClick={handleVerify}
                startIcon={<CheckCircleIcon />}
                sx={{ px: 4 }}
              >
                Yes, I approve this testimonial
              </Button>

              <Button 
                variant="outlined"
                color="error"
                size="large"
                startIcon={<CancelIcon />}
              >
                No, this needs changes
              </Button>
            </Box>
          </Box>
        </Box>
      </Fade>
    </Container>
  );
};

export default VerifyPage;
